			return fmt.Errorf("expanding test CA endpoint '%s': %v", iss.TestCA, err)
		}
		iss.TestCA = testCA
	}
```

`autoexport.WithFallbackMetricProducer(...)` is called but its return value is not used/passed into `autoexport.NewMetricReader`. If this is an option constructor (as the `With*` naming suggests), it will be ignored and the Prometheus registry won’t actually be used as the fallback producer, meaning OTLP export may be empty unless users set `OTEL_METRICS_PRODUCERS`. Pass the option to `autoexport.NewMetricReader` (or otherwise attach the producer to the reader/provider) so the intended fallback is applied.
```suggestion

	reader, err := autoexport.NewMetricReader(
		ctx,
		autoexport.WithFallbackMetricProducer(func(context.Context) (sdkmetric.Producer, error) {
			return otelprom.NewMetricProducer(otelprom.WithGatherer(reg)), nil
		}),
	)
